={
  "model": "gpt-5-mini",
  "input": [
    {
      "role": "system",
      "content": "You create Shopify product listings. Return ONLY valid JSON. No markdown. No code fences."
    },
    {
      "role": "user",
      "content": "Create a Shopify product listing.\\n\\nPRODUCT DATA:\\nTitle: {{ $json.context.title }}\\nSupplier: {{ $json.context.supplier }}\\nSupplier URL: {{ $json.context.supplier_url }}\\nCost: {{ $json.context.cost }}\\nSuggested price: {{ $json.context.suggested_price }}\\nWhy it wins: {{ $json.context.why_it_wins }}\\nRisks: {{ $json.context.risks }}\\nSEO keywords: {{ $json.context.seo_keywords }}\\nImage URLs: {{ ($json.context.image_urls || []).join(' | ') }}\\n\\nREQUIREMENTS:\\n- descriptionHtml must be clean Shopify-safe HTML (only: <p>, <ul>, <li>, <strong>, <h2>, <br>).\\n- No medical claims.\\n- price must be the suggested_price.\\n- compare_at_price must always be present: number OR null.\\n- tags: 6-12 short tags.\\n- sku: short, simple, uppercase, no spaces.\\n\\nReturn JSON with: title, descriptionHtml, tags, seo_title, seo_description, sku, price, compare_at_price, image_urls."
    }
  ],
  "text": {
    "format": {
      "type": "json_schema",
      "name": "listing",
      "strict": true,
      "schema": {
        "type": "object",
        "additionalProperties": false,
        "properties": {
          "title": { "type": "string" },
          "descriptionHtml": { "type": "string" },
          "tags": { "type": "array", "items": { "type": "string" } },
          "seo_title": { "type": "string" },
          "seo_description": { "type": "string" },
          "sku": { "type": "string" },
          "price": { "type": "number" },
          "compare_at_price": { "anyOf": [ { "type": "number" }, { "type": "null" } ] },
          "image_urls": { "type": "array", "items": { "type": "string" } }
        },
        "required": [
          "title",
          "descriptionHtml",
          "tags",
          "seo_title",
          "seo_description",
          "sku",
          "price",
          "compare_at_price",
          "image_urls"
        ]
      }
    }
  }
}

parameters.jsCode:
// Input is one Airtable product record at a time (from Loop Over Items)

const p = items[0].json;

// image_urls in your table looks newline-separated. We'll support commas too.
const raw = (p.image_urls || "").trim();

const imageUrls = raw
  .split(/\s*[\n,]\s*/g)        // split by newline OR comma
  .map(s => s.trim())
  .filter(Boolean)
  .slice(0, 3);                 // Shopify: keep it simple, max 3 images

// Build a clean prompt context (we keep your original fields)
const context = {
  title: p.title,
  supplier: p.supplier,
  supplier_url: p.Supplier_url,  // capital S in Airtable output
  cost: Number(p.cost || 0),
  suggested_price: Number(p.suggested_price || 0),
  margin_multiplier: Number(p.margin_multiplier || 0),
  why_it_wins: p.why_it_wins || "",
  risks: p.risks || "",
  seo_keywords: p.seo_keywords || "",
  image_urls: imageUrls,
  fingerprint: p.fingerprint || "",
  airtable_record_id: p.id
};

return [{ json: { airtable: p, context } }];

