parameters.jsCode:
const res = items[0].json;

// 1) If Shopify returned top-level GraphQL errors, stop and show them
if (Array.isArray(res.errors) && res.errors.length) {
  throw new Error("Shopify GraphQL errors: " + JSON.stringify(res.errors));
}

// 2) Make sure productCreate exists
const pc = res.data?.productCreate;
if (!pc) {
  throw new Error("No data.productCreate in response: " + JSON.stringify(res).slice(0, 800));
}

// 3) Shopify userErrors (these are different from top-level errors)
const userErrors = pc.userErrors || [];
if (userErrors.length) {
  throw new Error("Shopify productCreate userErrors: " + JSON.stringify(userErrors));
}

// 4) Extract IDs
const product = pc.product;
if (!product?.id) throw new Error("No product returned: " + JSON.stringify(pc).slice(0, 800));

const productId = product.id;
const variantId = product.variants?.nodes?.[0]?.id || null;
const handle = product.handle || null;

// 5) Pull forward your listing/context from Node 6 (rename if needed)
const prev = $items("6 - Parse Listing")[0].json;

return [{
  json: {
    ...prev,
    shopify: { productId, variantId, handle }
  }
}];

// We want the JSON text from Responses API. This parser is defensive.
const input = items[0].json;

// Find a text chunk anywhere in response.output
let text = null;

if (Array.isArray(input.output)) {
  for (const out of input.output) {
    if (Array.isArray(out.content)) {
      for (const c of out.content) {
        if (typeof c.text === "string") {
          text = c.text;
          break;
        }
      }
    }
    if (text) break;
  }
}

if (!text) {
  throw new Error("OpenAI response did not contain output.content.text");
}

let listing;
try {
  listing = JSON.parse(text);
} catch (e) {
  throw new Error("Failed to parse listing JSON. Raw text: " + text.slice(0, 500));
}

// Bring forward the Airtable + context from Node 4 (available via $input.all() only if wired)
// In n8n, easiest is: rely on previous node data already merged in chain.
// If your chain is Node4 -> Node5 -> Node6, then Node5 input isn't carried.
// So we re-fetch Node4's item using $items().
const prev = $items("4 - Prepare Context")[0].json; // Node 4 is named "Code" by default - rename it if you want.

return [{
  json: {
    airtable: prev.airtable,
    context: prev.context,
    listing
  }
}];

// Node 9 - Build Media Inputs (safe version: no redeclare issues)

var input = $json || {};

// These might exist in different shapes depending on your previous nodes
var listingObj = (input && input.listing) ? input.listing : {};
var airtableObj = (input && input.airtable) ? input.airtable : input;

// Grab urls from either listing.image_urls or airtable.image_urls
var raw = (listingObj && listingObj.image_urls != null)
  ? listingObj.image_urls
  : (airtableObj && airtableObj.image_urls != null)
    ? airtableObj.image_urls
    : [];

// Normalize to an array of strings
var urls = [];
if (Array.isArray(raw)) {
  urls = raw;
} else if (typeof raw === "string") {
  urls = raw
    .split(/\s*,\s*|\s*\n\s*|\s*\|\s*/g) // comma OR newline OR pipe separated
    .map(s => s.trim())
    .filter(Boolean);
} else {
  urls = [];
}

// Keep only real http(s) links, limit count
urls = urls
  .filter(u => typeof u === "string" && /^https?:\/\//i.test(u))
  .slice(0, 10);

// Build Shopify CreateMediaInput[]
var altText = (listingObj && listingObj.title) ? listingObj.title : (airtableObj.title || "Product image");

var media = urls.map(u => ({
  mediaContentType: "IMAGE",
  originalSource: u,
  alt: altText
}));

return [
  {
    json: {
      ...input,
      media,
      media_urls: urls
    }
  }
];

